-- Restore correct rarity values for all units from the original seed data.
-- The sync script had a bug where parseRarityMap() returned empty,
-- causing all units with ID > 56 to be classified as RARE.
-- This migration restores the correct rarity for all 6 tiers.

-- NORMAL: 10 units
UPDATE "Unit" SET "category" = 'NORMAL'::"UnitCategory", "sortOrder" = 0 + "unitNumber"
WHERE "unitNumber" IN (0, 1, 2, 3, 4, 5, 6, 7, 8, 643);

